import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import api from '../services/api';

const QuestionList = () => {
  const [questions, setQuestions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    console.log('[QuestionList] Mounted – starting data fetch');

    const loadQuestions = async () => {
      try {
        console.log('[QuestionList] Calling api.get("/questions")');
        const response = await api.get('/questions');

        console.log('[QuestionList] Full response:', response);
        console.log('[QuestionList] Data type:', typeof response.data);
        console.log('[QuestionList] Data content:', response.data);

        // Force array + filter invalid items
        const data = Array.isArray(response.data) ? response.data : [];
        const validQuestions = data.filter(q => q && q._id && q.title);

        console.log('[QuestionList] Valid questions count:', validQuestions.length);
        setQuestions(validQuestions);
      } catch (err) {
        console.error('[QuestionList] Fetch error:', err);
        console.error('[QuestionList] Error message:', err.message);
        if (err.response) {
          console.error('[QuestionList] Server response:', err.response.data);
          console.error('[QuestionList] Status code:', err.response.status);
        }
        setError('Failed to load questions. Check console (F12) for details.');
      } finally {
        setLoading(false);
      }
    };

    loadQuestions();
  }, []);

  // ────────────────────────────────────────────────
  // Render logic – very defensive
  // ────────────────────────────────────────────────

  if (loading) {
    return (
      <div style={{ padding: '40px', color: '#0066cc', fontSize: '18px' }}>
        Loading questions...
      </div>
    );
  }

  if (error) {
    return (
      <div style={{ padding: '40px', color: 'red', fontSize: '18px', background: '#fff0f0' }}>
        {error}
        <br /><br />
        <small>Open browser DevTools (F12 → Console) to see detailed logs</small>
      </div>
    );
  }

  return (
    <div style={{ padding: '0 20px 40px' }}>
      <h2 style={{ margin: '0 0 20px' }}>
        Questions {questions.length > 0 ? `(${questions.length})` : ''}
      </h2>

      {questions.length === 0 ? (
        <div style={{ color: '#555', fontSize: '17px', lineHeight: 1.6 }}>
          No questions found yet.<br />
          <Link to="/ask" style={{ color: '#007bff', fontWeight: 'bold' }}>
            Ask the first question →
          </Link>
        </div>
      ) : (
        <div>
          {questions.map((q) => (
            <div
              key={q._id || `fallback-${Math.random()}`}
              style={{
                padding: '16px 0',
                borderBottom: '1px solid #eee',
                marginBottom: '8px',
              }}
            >
              <Link
                to={`/questions/${q._id}`}
                style={{
                  fontSize: '18px',
                  fontWeight: '600',
                  color: '#1a73e8',
                  textDecoration: 'none',
                }}
              >
                {q.title || '(no title)'}
              </Link>

              <div style={{ marginTop: '6px', color: '#666', fontSize: '14px' }}>
                Votes: {Number(q.votes) || 0}
                {q.tags && Array.isArray(q.tags) && q.tags.length > 0 && (
                  <span style={{ marginLeft: '20px' }}>
                    Tags: {q.tags.join(', ')}
                  </span>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default QuestionList;
